// Normalize payload across HeyReach and LinkedHelper shapes into a unified event.
// Detect engine by presence of key fields.
const raw = items[0].json.body || items[0].json;

let engine, event_type, sender_url, sender_public_id, body_text, conversation_id, engine_message_id;

if (raw.eventType) {
  // HeyReach shape
  engine = 'heyreach';
  event_type = raw.eventType; // e.g. 'MESSAGE_RECEIVED', 'CONNECTION_ACCEPTED'
  sender_url = raw.lead?.profileUrl || raw.profileUrl || null;
  sender_public_id = raw.lead?.publicIdentifier || null;
  body_text = raw.message?.text || raw.messageBody || '';
  conversation_id = raw.conversationId || raw.threadId || null;
  engine_message_id = raw.messageId || null;
} else if (raw.event || raw.actionType) {
  // LinkedHelper shape
  engine = 'linkedhelper';
  event_type = raw.event || raw.actionType; // e.g. 'new_message', 'invitation_accepted'
  sender_url = raw.profile?.url || raw.profileUrl || null;
  sender_public_id = raw.profile?.publicId || null;
  body_text = raw.text || raw.messageText || '';
  conversation_id = raw.conversationId || null;
  engine_message_id = raw.id || null;
} else {
  return [{ json: { error: 'unknown payload shape', raw } }];
}

// Classify reply (same keyword rules as email sibling, adapted for DM brevity)
const body_lower = (body_text || '').toLowerCase();
const rules = [
  { type: 'opt_out',         re: /\b(stop|unsubscribe|remove|opt[- ]?out|do not contact|non contattarmi|rimuovi)\b/ },
  { type: 'auto_reply',      re: /\b(out of office|ooo|on leave|vacation|ferie|assente)\b/ },
  { type: 'interested',      re: /\b(interested|interessato|sounds good|let'?s chat|book|calendar|demo|call|fissa|prenotiamo)\b/ },
  { type: 'objection',       re: /\b(too expensive|price|budget|already use|happy with|not now|maybe later|troppo caro|ne parliamo poi)\b/ },
  { type: 'not_interested',  re: /\b(not interested|no thanks|pass|not a fit|not relevant|non interessato|non fa per me)\b/ }
];
let reply_type = 'other';
if (event_type && event_type.toLowerCase().includes('connection') && event_type.toLowerCase().includes('accept')) {
  reply_type = 'connection_accept';
} else {
  for (const r of rules) if (r.re.test(body_lower)) { reply_type = r.type; break; }
}

const sentiment = reply_type === 'interested' ? 'positive'
  : (reply_type === 'not_interested' || reply_type === 'opt_out') ? 'negative'
  : 'neutral';

return [{ json: { engine, event_type, sender_url, sender_public_id, body_text, conversation_id, engine_message_id, reply_type, sentiment, raw } }];

